## Objective
Create the frontend app shell with BrowserRouter and routes for the initial customer and admin pages.

## Files to write

### frontend/src/App.tsx
```tsx
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';

function Placeholder({ title }: { title: string }) {
  return <div style={{ padding: 24 }}>{title}</div>;
}

export default function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Placeholder title="Menu" />} />
        <Route path="/cart" element={<Placeholder title="Cart" />} />
        <Route path="/checkout" element={<Placeholder title="Checkout" />} />
        <Route path="/confirmation/:orderId" element={<Placeholder title="Confirmation" />} />
        <Route path="/status/:orderId" element={<Placeholder title="Order Status" />} />
        <Route path="/admin" element={<Placeholder title="Admin" />} />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </BrowserRouter>
  );
}
```
